import React, { useState } from "react";
import axios from "axios";

const TranscriptInput = () => {
  const [file, setFile] = useState(null);
  const [transcript, setTranscript] = useState("");
  const [summary, setSummary] = useState("");
  const [actionItems, setActionItems] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => setFile(e.target.files[0]);

  const handleUpload = async () => {
  if (!file) return alert("Please select a file first!");
  setLoading(true);

  const formData = new FormData();
  formData.append('file', file);

  try {
    const res = await axios.post('http://localhost:8000/transcribe', formData);

    // Check if valid response structure
    if (!res.data || !res.data.transcript) {
      throw new Error("Invalid response from server");
    }

    setTranscript(res.data.transcript);
    setSummary(
      res.data.summary?.map((s) => s.summary).join('\n') || 'No summary available'
    );
    setActionItems(res.data.action_items || []);
  } catch (err) {
    console.error('Error uploading:', err);
    alert("❌ Failed to upload or backend is not responding. Please make sure the backend is running.");
  } finally {
    setLoading(false); // This will run whether the try succeeds or fails
  }
};
  // const handleUpload = async () => {
  //   if (!file) return alert("Please select a file first!");
  //   setLoading(true);

  //   const formData = new FormData();
  //   formData.append("file", file);

  //   try {
  //     const res = await axios.post("http://localhost:8000/transcribe", formData);
  //     setTranscript(res.data.transcript);
  //     setSummary(
  //       res.data.summary?.map((s) => s.summary).join("\n") || "No summary available"
  //     );
  //     setActionItems(res.data.action_items || []);
  //   } catch (err) {
  //     console.error("Error uploading:", err);
  //   } finally {
  //     setLoading(false);
  //   }
  // };

  const handleClear = () => {
    setFile(null);
    setTranscript("");
    setSummary("");
    setActionItems([]);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(generateExportText());
    alert("Copied to clipboard!");
  };

  const handleDownload = () => {
    const blob = new Blob([generateExportText()], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "meeting-summary.txt";
    a.click();
    URL.revokeObjectURL(url);
  };

  const generateMailtoLink = () =>
    `mailto:?subject=Meeting Summary&body=${encodeURIComponent(generateExportText())}`;

  const generateExportText = () => {
    let text = "📝 Meeting Summary:\n";
    text += summary + "\n\n";
    text += "✅ Action Items:\n";
    text += Array.isArray(actionItems)
      ? actionItems
          .map(
            (item) =>
              `- ${item.task} [Owner: ${item.owner}] [Deadline: ${item.deadline}]`
          )
          .join("\n")
      : "No action items.";
    return text;
  };

  const handleExportToNotion = () => {
    alert("🔧 Export to Notion functionality coming soon!");
  };

  return (
    <div className="bg-gray-900 border border-teal-500 rounded-xl p-6 shadow-lg text-gray-100">
      <h2 className="text-xl font-semibold text-teal-400 mb-4">📄 Upload File</h2>
      <input
        type="file"
        onChange={handleFileChange}
        className="block mb-4 text-gray-300"
      />
      <div className="flex gap-4 mb-4">
        <button
          onClick={handleUpload}
          disabled={loading}
          className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded"
        >
          {loading ? "Processing..." : "Upload & Transcribe"}
        </button>
        <button
          onClick={handleClear}
          className="bg-gray-700 hover:bg-gray-600 text-gray-300 px-4 py-2 rounded"
        >
          Clear
        </button>
      </div>

      {summary && (
        <div className="mb-4">
          <h4 className="text-teal-300 mb-2">📝 Summary</h4>
          <p className="whitespace-pre-wrap text-gray-300">{summary}</p>
        </div>
      )}

      {Array.isArray(actionItems) && actionItems.length > 0 && (
        <div className="mb-4">
          <h4 className="text-green-400 mb-2">✅ Action Items</h4>
          <ul className="list-disc list-inside text-gray-300">
            {actionItems.map((item, index) => (
              <li key={index}>
                <strong>Task:</strong> {item.task} <br />
                <strong>Owner:</strong> {item.owner} <br />
                <strong>Deadline:</strong> {item.deadline}
              </li>
            ))}
          </ul>
        </div>
      )}

      {(summary || actionItems.length > 0) && (
        <div className="flex flex-col gap-2 mt-4">
          <button
            onClick={handleCopy}
            className="bg-gray-700 hover:bg-gray-600 text-white px-4 py-2 rounded"
          >
            📋 Copy to Clipboard
          </button>
          <button
            onClick={handleDownload}
            className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded"
          >
            💾 Download Summary
          </button>
          <a
            href={generateMailtoLink()}
            className="bg-purple-600 hover:bg-purple-700 text-white px-4 py-2 rounded text-center"
          >
            📧 Send via Email
          </a>
          <button
            onClick={handleExportToNotion}
            className="bg-yellow-500 hover:bg-yellow-600 text-white px-4 py-2 rounded"
          >
            📓 Export to Notion
          </button>
        </div>
      )}
    </div>
  );
};

export default TranscriptInput;
